// Element references
const signUpScreen = $(".sign_up_screen"),
    authenticationScreen = $(".authentication_screen"),
    authenticationScreen2 = $(".authentication_screen2"),
    loginContent = $(".login_content"),
    nameValidation = $("#name"),
    numberValidation = $("#username"),
    email = $("#email"),
    phone = $("#phone"),
    otpBox1 = $("#otp1"),
    otpBox2 = $("#otp2"),
    otpBox3 = $("#otp3"),
    otpBox4 = $("#otp4"),
    termsCheckbox = $('#sign_up_check input[type="checkbox"]'),
    loginPopup = $("#loginPopup"),
    openLoginPopup = $("#openLoginPopup"),
    closeLoginPopupBtn = $(".loginPopupClose"),
    signupPopup = $("#signupPopup"),
    openSignupPopup = $("#openSignupPopup"),
    closeSignupPopupBtn = $(".signupClose"),
    errorMsg = $("#errorMsg"),
    errorMsg2 = $("#errorMsg2"),
    windowValue = $("#openSignupPopup").data("window-open");

function resetOtpBoxes() {
    otpBox1.val("");
    otpBox2.val("");
    otpBox3.val("");
    otpBox4.val("");
    $("#otp01").val("");
    $("#otp02").val("");
    $("#otp03").val("");
    $("#otp04").val("");
    loginContent.css("display", "block");
    authenticationScreen2.css("display", "none");
}

function openPopup(popupElement, openButton, closeButton) {
    if (windowValue == "1") {
        $("#sign_up_as").text("Sign Up As Coach");
    } else if (windowValue == "2") {
        $("#sign_up_as").text("Sign Up As Academy");
    } else if (windowValue == "3") {
        $("#sign_up_as").text("Sign Up As Player");
    } else {
        $("#sign_up_as").text("Sign Up");
    }

    if (openButton) {
        openButton.on("click", function () {
            popupElement.css("display", "block");

            if (popupElement.is(signupPopup)) {
                authenticationScreen.css("display", "none");
                signUpScreen.css("display", "block");
                nameValidation.val("");
                email.val("");
                phone.val("");
                otpBox1.val("");
                otpBox2.val("");
                otpBox3.val("");
                otpBox4.val("");
                errorMsg.addClass("d-none");
                errorMsg2.addClass("d-none");
            } else {
                authenticationScreen2.css("display", "none");
                loginContent.css("display", "block");
                numberValidation.val("");
                $("#otp01").val("");
                $("#otp02").val("");
                $("#otp03").val("");
                $("#otp04").val("");
                $("#errorMsgLogin").addClass("d-none");
                $("#errorMsgLogin2").addClass("d-none");
            }
        });
    }

    if (closeButton) {
        closeButton.on("click", function () {
            popupElement.css("display", "none");
        });
    }

    $(document).on("click", function (event) {
        if ($(event.target).is(popupElement)) {
            closePopup(popupElement);
        }
    });

    $(document).on("keydown", function (event) {
        if (event.key === "Escape") {
            closePopup(popupElement);
        }
    });
}

function closePopup(popupElement) {
    popupElement.css("display", "none");
}

document.cookie = "profile_viewer_uid=" + windowValue;
openPopup(loginPopup, openLoginPopup, closeLoginPopupBtn);
openPopup(signupPopup, openSignupPopup, closeSignupPopupBtn);

const createAccountButton = $(".create_account"),
    haveAccountButton = $(".have_account");

function showSignUpScreen() {
    signUpScreen.css("display", "block");
    authenticationScreen.css("display", "none");
}

createAccountButton.on("click", function () {
    loginPopup.css("display", "none");
    signupPopup.css("display", "block");
});

haveAccountButton.on("click", function () {
    signupPopup.css("display", "none");
    loginPopup.css("display", "block");
});

const otpInputs = $(".mob_otp_input");

function startCountdown() {
    let timeLeft = 120;
    const countdownTimer = setInterval(function () {
        const minutes = Math.floor(timeLeft / 60);
        const seconds = timeLeft % 60;
        if (timeLeft <= 0) {
            clearInterval(countdownTimer);
            $("#resend-otp-signup").show();
            $("#time").hide();
        } else {
            $("#time").text(`RESENT OTP IN ${minutes}m ${seconds}s`);
            timeLeft--;
        }
    }, 1000);
}

function checkUserDetailsExists(type, value) {
    const inputField = type === "email" ? $("#email") : $("#phone");

    function validate() {
        $.ajax({
            type: "POST",
            url: "/user-details/check",
            data: {
                _token: $('meta[name="csrf-token"]').attr("content"),
                mobile: value,
                email: value,
                type: type,
            },
            dataType: "json",
            success(response) {
                if (response.status === 1) {
                    inputField.removeClass("text-success").addClass("text-danger");
                } else {
                    inputField.removeClass("text-danger").addClass("text-success");
                }
            },
            error(response) {
                alert(response);
            },
        });
    }

    if (type === "mobile") {
        if (value.length !== 10) {
            inputField.addClass("text-danger");
        } else {
            inputField.removeClass("text-danger");
            validate();
        }
    } else if (type === "email") {
        const emailPattern = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
        if (emailPattern.test(value)) {
            inputField.removeClass("text-danger");
            validate();
        } else {
            inputField.addClass("text-danger");
        }
    }
}

function formatName(name) {
    return name
        .split(" ")
        .map(word => word.charAt(0).toUpperCase() + word.slice(1).toLowerCase())
        .join(" ");
}

otpInputs.on("input", function (event) {
    const currentIndex = otpInputs.index(this);
    if (event.target.value.length === 1) {
        if (currentIndex < otpInputs.length - 1) {
            otpInputs.eq(currentIndex + 1).focus();
        }
    } else if (event.target.value.length === 0) {
        if (currentIndex > 0) {
            otpInputs.eq(currentIndex - 1).focus();
        }
    }
});

otpInputs.on("keydown", function (event) {
    const currentIndex = otpInputs.index(this);
    if (event.key === "Backspace" && event.target.value.length === 0 && currentIndex > 0) {
        otpInputs.eq(currentIndex - 1).focus();
    }
});

otpInputs.on("keypress", function (event) {
    if ($(this).val().length >= 1) {
        event.preventDefault();
    }
});

$("#otp1, #otp2, #otp3, #otp4").on("input", function () {
    const allFilled = $("#otp1, #otp2, #otp3, #otp4").toArray().every(input => $(input).val() !== "");
    if (allFilled) {
        $("#btn-signup").prop("disabled", false).removeClass("disable_btn").addClass("signup_verify_btn");
    } else {
        $("#btn-signup").prop("disabled", true).addClass("disable_btn").removeClass("signup_verify_btn");
    }
});

$(document).ready(function () {
    $("#getOtpBtn").on("click", function () {
        if (nameValidation.val().length === 0) {
            errorMsg.text("Please Enter Your Name").removeClass("d-none");
        } else if (email.val().length === 0) {
            errorMsg.text("Please Enter Your Email").removeClass("d-none");
        } else if (phone.val().length === 0) {
            errorMsg.text("Please Enter Your Phone Number").removeClass("d-none");
        } else if (phone.val().length !== 10) {
            errorMsg.text("Please Enter 10 digits Phone Number").removeClass("d-none");
        } else if (termsCheckbox.prop("checked")) {
            const userDetails = {
                email: email.val(),
                phone: phone.val(),
            };

            function sendOtp(phone, type) {
                $.ajax({
                    type: "POST",
                    url: "/otp/send",
                    data: {
                        _token: $('meta[name="csrf-token"]').attr("content"),
                        phone: phone,
                        type: type,
                    },
                    dataType: "json",
                    success(response) {
                        if (response.status === 0 && type === "signup_otp") {
                            errorMsg.text(response.message).removeClass("d-none");
                        } else if (response.status === 1 && type === "resend_signup_otp") {
                            $("#btn-signup").prop("disabled", true).addClass("disable_btn").removeClass("signup_verify_btn");
                            $("#resend-otp-signup").hide();
                            $("#time").show();
                            startCountdown();
                        } else {
                            $("#btn-signup").prop("disabled", true).addClass("disable_btn").removeClass("signup_verify_btn");
                            signUpScreen.css("display", "none");
                            authenticationScreen.css("display", "block");
                            otpBox1.focus();
                            startCountdown();
                        }
                    },
                    error(response) {
                        errorMsg.text(response).removeClass("d-none");
                    },
                });
            }

            $("#resend-otp-signup").click(function () {
                sendOtp(phone.val(), "resend_signup_otp");
            });

            $.ajax({
                type: "POST",
                url: "/api/check-user-exist",
                data: {
                    _token: $('meta[name="csrf-token"]').attr("content"),
                    phone: userDetails.phone,
                    email: userDetails.email,
                },
                dataType: "json",
                success(response) {
                    if (response.status === 1) {
                        errorMsg.text("User Already Exists.").removeClass("d-none");
                    } else {
                        sendOtp(userDetails.phone, "signup_otp");
                    }
                },
                error(response) {
                    errorMsg.text(response).removeClass("d-none");
                },
            });

            $("#phoneNumberSpan").text("+91" + phone.val());
        } else {
            errorMsg.text("Please accept the Terms and Privacy Policy").removeClass("d-none");
        }
    });

    otpBox4.on("input", function () {
        if (otpBox1.val() && otpBox2.val() && otpBox3.val() && otpBox4.val()) {
            const name = formatName($("#name").val()),
                phoneNumber = $("#phone").val(),
                emailAddress = $("#email").val().toLowerCase(),
                typeId = $("#option").val() || windowValue,
                otp = otpBox1.val() + otpBox2.val() + otpBox3.val() + otpBox4.val();

            $.ajax({
                type: "POST",
                url: "/register/validate",
                data: {
                    _token: $('meta[name="csrf-token"]').attr("content"),
                    name: name,
                    phone: phoneNumber,
                    email: emailAddress,
                    type_id: typeId,
                    otp: otp,
                },
                success(response) {
                    if (response.status === 1) {
                        if (response.redirect_url) {
                            window.location.href = response.redirect_url;
                        } else {
                            location.reload();
                        }
                    } else if (response.status === 0) {
                        errorMsg2.text(response.message).removeClass("d-none");
                    }
                },
                error(response) {
                    errorMsg2.text(JSON.stringify(response)).removeClass("d-none");
                },
            });
        }
    });
});

email.on("focusout", function () {
    if ($(this).val().length > 1) {
        checkUserDetailsExists("email", $(this).val());
    }
});

phone.on("focusout", function () {
    if ($(this).val().length > 1) {
        checkUserDetailsExists("mobile", $(this).val());
    }
});

$(document).ready(function () {
    $("#option").change(function () {
        const optionValue = $(this).val();
        if (optionValue == "1") {
            $("#sign_up_as").text("Sign Up As Coach");
        } else if (optionValue == "2") {
            $("#sign_up_as").text("Sign Up As Academy");
        } else if (optionValue == "3") {
            $("#sign_up_as").text("Sign Up As Player");
        } else {
            $("#sign_up_as").text("Sign Up");
        }
    });
});

$("#btn-location").click(function () {
    if (navigator.geolocation) {
        navigator.geolocation.getCurrentPosition(
            function (position) {
                const latitude = position.coords.latitude;
                const longitude = position.coords.longitude;
                const coordinates = `${latitude},${longitude}`;
            },
            function (error) {
                console.log(error);
            }
        );
    } else {
        console.log("Geolocation is not supported by this browser.");
    }
});
